import { useState } from "react";
import { useNavigate } from "react-router-dom";
import PhoneFrame from "../components/PhoneFrame";
import ProgressBar from "../components/ProgressBar";

const options = [
  { icon: "✈️", bg: true, name: "Flight", chip: "Best value", sub: "IndiGo · 6E-234 · 2h 40m", price: "₹3,200", dur: "Non-stop" },
  { icon: "✈️", bg: false, name: "Flight", sub: "Air India · AI-891 · 3h 10m", price: "₹4,100", dur: "1 stop" },
  { icon: "🚂", bg: false, name: "Train", sub: "Himachal Exp · 2 days", price: "₹1,400", dur: "Sleeper AC" },
  { icon: "🚌", bg: false, name: "Bus", sub: "HRTC Volvo · 36h", price: "₹900", dur: "Overnight" },
];

const Travel = () => {
  const [selected, setSelected] = useState(0);
  const navigate = useNavigate();
  return (
    <PhoneFrame time="9:43">
      <div className="app-header">
        <span className="back-link" onClick={() => navigate("/mode-select")}>← Back</span>
        <span className="logo-text">travel<span className="logo-dot">blurry</span></span>
        <span className="header-action" onClick={() => navigate("/plan")}>Skip all</span>
      </div>

      <div className="content-scroll">
        <ProgressBar doneCount={1} />
        <div className="screen-title">How will you travel?</div>
        <div className="screen-sub">Kolkata → Manali · Outbound journey</div>

        <div className="section-label">Recommended for you</div>
        {options.map((o, i) => (
          <div key={i}>
            {i === 1 && <div className="section-label" style={{ marginTop: 12 }}>Other options</div>}
            <div className={`travel-opt${selected === i ? " selected" : ""}`} onClick={() => setSelected(i)}>
              <div className={`travel-opt-icon${o.bg ? " blue-bg" : ""}`}>{o.icon}</div>
              <div className="travel-opt-info">
                <div className="travel-opt-name">{o.name}{o.chip && <span className="rec-chip">{o.chip}</span>}</div>
                <div className="travel-opt-sub">{o.sub}</div>
              </div>
              <div>
                <div className="travel-opt-price">{o.price}</div>
                <div className="travel-opt-dur">{o.dur}</div>
              </div>
              <div className={`radio-circle${selected === i ? " on" : ""}`}></div>
            </div>
          </div>
        ))}
        <div className="helper-text">You can change this later from the final plan</div>
      </div>

      <div className="sticky-bottom">
        <button className="cta-btn" onClick={() => navigate("/stay")}>Confirm transport →</button>
        <div className="skip-link" onClick={() => navigate("/stay")}>Skip this step</div>
      </div>
    </PhoneFrame>
  );
};

export default Travel;
